import app from 'flarum/admin/app';
import ExtensionPage from 'flarum/admin/components/ExtensionPage';
import Button from 'flarum/common/components/Button';
import DiscussionsBinPage from './DiscussionsBinPage';
import PostsBinPage from './PostsBinPage';
export default class SettingsPage extends ExtensionPage {
  content() {
    const bin = m.route.param().bin || 'discussions-bin';
    return m("div", {
      className: "ExtensionPage-settings RecycleBin"
    }, m("div", {
      className: "RecycleBin-menu"
    }, m("div", {
      className: "container"
    }, this.menuButtons(bin))), m("div", {
      className: "container RecycleBin-container"
    }, this.pageContent(bin)));
  }

  // Return button menus
  menuButtons(bin) {
    return [Button.component({
      className: "Button ".concat(bin === 'discussions-bin' ? 'item-selected' : ''),
      onclick: () => m.route.set(app.route('extension', {
        id: 'walsgit-recycle-bin',
        bin: 'discussions-bin',
        page: 1
      })),
      icon: 'fas fa-comment'
    }, app.translator.trans('walsgit-recycle-bin.admin.discussions_bin')), Button.component({
      className: "Button ".concat(bin === 'posts-bin' ? 'item-selected' : ''),
      onclick: () => m.route.set(app.route('extension', {
        id: 'walsgit-recycle-bin',
        bin: 'posts-bin',
        page: 1
      })),
      icon: 'far fa-comment-dots'
    }, app.translator.trans('walsgit-recycle-bin.admin.posts_bin'))];
  }
  pageContent(bin) {
    if (bin === 'posts-bin') {
      return m(PostsBinPage, null);
    }
    // Default Discussions bin
    return m(DiscussionsBinPage, null);
  }
}
flarum.reg.add('walsgit-recycle-bin', 'admin/components/SettingsPage', SettingsPage);